  "inlineSchema": "// Schéma Prisma pour PostgreSQL (adaptateur 2)\n// Pour activer : DB_ADAPTER=postgresql dans les variables d'environnement\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel Client {\n  id             String     @id\n  nom            String\n  email          String     @unique\n  adresse        String\n  telephone      String?\n  pointsFidelite Int        @default(0)\n  commandes      Commande[]\n}\n\nmodel Restaurant {\n  id             String     @id\n  nom            String\n  adresse        String\n  latitude       Float\n  longitude      Float\n  proprietaireId String\n  imageUrl       String?\n  categories     String[]\n  plats          PlatMenu[]\n  commandes      Commande[]\n}\n\nmodel PlatMenu {\n  id              String     @id\n  nom             String\n  description     String\n  prixCentimes    Int\n  allergenes      String[]\n  stockJournalier Int\n  restaurantId    String\n  imageUrl        String?\n  actif           Boolean    @default(true)\n  categorie       String     @default(\"PLAT\") // \"PLAT\" ou \"BOISSON\"\n  restaurant      Restaurant @relation(fields: [restaurantId], references: [id])\n}\n\nmodel FavoriRestaurant {\n  clientId     String\n  restaurantId String\n\n  @@id([clientId, restaurantId])\n}\n\nmodel FavoriPlat {\n  clientId String\n  platId   String\n\n  @@id([clientId, platId])\n}\n\nmodel AvisLivreur {\n  id          String   @id @default(uuid())\n  commandeId  String   @unique\n  livreurId   String\n  clientId    String\n  note        Int // 1 à 5\n  commentaire String?\n  creeLe      DateTime @default(now())\n}\n\nmodel Commande {\n  id                   String            @id\n  clientId             String\n  restaurantId         String\n  statut               String\n  prixPlatsCentimes    Int\n  fraisLivCentimes     Int\n  fraisServiceCentimes Int\n  reductionCentimes    Int               @default(0)\n  adresseLivraison     String\n  livreurId            String?\n  tempsPreparation     Int?\n  latitudeLivraison    Float?\n  longitudeLivraison   Float?\n  creeLe               DateTime          @default(now())\n  client               Client            @relation(fields: [clientId], references: [id])\n  restaurant           Restaurant        @relation(fields: [restaurantId], references: [id])\n  articles             ArticleCommande[]\n  facture              Facture?\n}\n\nmodel ArticleCommande {\n  id           String   @id @default(uuid())\n  commandeId   String\n  menuItemId   String\n  nom          String\n  prixCentimes Int\n  quantite     Int\n  restaurantId String\n  commande     Commande @relation(fields: [commandeId], references: [id])\n}\n\nmodel Facture {\n  id         String   @id\n  commandeId String   @unique\n  clientId   String\n  genereLe   DateTime @default(now())\n  total      Int\n  commande   Commande @relation(fields: [commandeId], references: [id])\n}\n\nmodel Livreur {\n  id                   String   @id\n  nom                  String\n  telephone            String\n  latitude             Float\n  longitude            Float\n  statut               String   @default(\"INDISPONIBLE\")\n  portefeuilleCentimes Int      @default(0)\n  estExpert            Boolean  @default(false)\n  commandesEnCoursIds  String[]\n  propositionsIds      String[]\n  currentRestaurantId  String?\n}\n\nmodel CompteUtilisateur {\n  id              String   @id\n  email           String   @unique\n  motDePasseHache String\n  role            String // \"CLIENT\", \"RESTAURATEUR\", \"LIVREUR\", \"ADMIN\"\n  profilId        String // ID du profil associé\n  estActif        Boolean  @default(true)\n  creeLe          DateTime @default(now())\n}\n\nmodel TicketSupport {\n  id       String          @id @default(uuid())\n  auteurId String\n  titre    String\n  statut   String          @default(\"OUVERT\") // \"OUVERT\", \"CLOS\"\n  estLu    Boolean         @default(false)\n  creeLe   DateTime        @default(now())\n  messages MessageTicket[]\n}\n\nmodel MessageTicket {\n  id       String        @id @default(uuid())\n  ticketId String\n  auteurId String\n  contenu  String\n  estAdmin Boolean       @default(false)\n  envoyeLe DateTime      @default(now())\n  ticket   TicketSupport @relation(fields: [ticketId], references: [id])\n}\n",
